const token = event.token || '';
if (!token) return { success: false, error: 'Token vazio' };

const url = 'https://api.movidesk.com/public/v1/tickets?token=' + token + '&$top=1&$select=id,subject,status';
try {
  const res = await fetch(url, { signal: AbortSignal.timeout(30000) });
  if (res.status === 403) {
    return { success: false, error: 'HTTP 403 — Token invalido ou sem permissao', statusCode: 403 };
  }
  if (res.status === 429) {
    return { success: false, error: 'HTTP 429 — Rate limit atingido. Tente novamente em 60 segundos.', statusCode: 429 };
  }
  if (!res.ok) {
    const body = await res.text();
    return { success: false, error: 'HTTP ' + res.status + ': ' + body.substring(0, 200), statusCode: res.status };
  }
  const data = await res.json();
  if (Array.isArray(data) && data.length > 0) {
    return {
      success: true,
      message: 'Token valido! Primeiro ticket: #' + data[0].id + ' — ' + (data[0].subject || '').substring(0, 50),
      statusCode: 200,
      sampleTicket: { id: data[0].id, subject: data[0].subject, status: data[0].status }
    };
  }
  return { success: true, message: 'Token valido (nenhum ticket retornado)', statusCode: 200 };
} catch (e) {
  return { success: false, error: 'Erro de conexao: ' + String(e.message || e).substring(0, 200) };
}
